import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getHealthAdvice = async (query: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `You are a helpful medical assistant for Aadharbhut Nagar Aspatal (Beltar Municipal Hospital). 
      Provide concise health advice in both English and Nepali (using Devanagari script). 
      User Query: ${query}. 
      Always state that this is AI advice and they should consult a real doctor for emergencies.`,
      config: {
        temperature: 0.7,
        topP: 0.8,
        topK: 40,
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "I'm sorry, I'm having trouble connecting right now. Please consult our on-duty medical officer.";
  }
};

import React from 'react';
import { ViewState } from '../types';
import { Hospital, Menu, X, User } from 'lucide-react';

interface NavbarProps {
  currentView: ViewState;
  setView: (view: ViewState) => void;
  isAdmin: boolean;
}

const Navbar: React.FC<NavbarProps> = ({ currentView, setView, isAdmin }) => {
  const [isOpen, setIsOpen] = React.useState(false);

  const navItems = [
    { label: 'Home', view: 'HOME' as ViewState },
    { label: 'Services', view: 'SERVICES' as ViewState },
    { label: 'Doctors', view: 'DOCTORS' as ViewState },
    { label: 'About', view: 'ABOUT' as ViewState },
  ];

  return (
    <nav className="bg-blue-800 text-white shadow-lg sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-20">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setView('HOME')}>
            <div className="p-2 bg-white rounded-full">
              <Hospital className="w-8 h-8 text-blue-800" />
            </div>
            <div>
              <h1 className="text-xl font-bold leading-none tracking-tight">आधारभूत नगर अस्पताल</h1>
              <p className="text-xs font-medium uppercase opacity-80">Beltar, Udayapur</p>
            </div>
          </div>

          {/* Desktop Nav */}
          <div className="hidden md:block">
            <div className="ml-10 flex items-baseline space-x-4">
              {navItems.map((item) => (
                <button
                  key={item.label}
                  onClick={() => setView(item.view)}
                  className={`px-3 py-2 rounded-md text-sm font-medium transition-colors hover:bg-blue-700 ${
                    currentView === item.view ? 'bg-blue-900' : ''
                  }`}
                >
                  {item.label}
                </button>
              ))}
              <button
                onClick={() => setView(isAdmin ? 'ADMIN_DASHBOARD' : 'ADMIN_LOGIN')}
                className="flex items-center gap-2 px-4 py-2 rounded-md text-sm font-bold bg-white text-blue-800 hover:bg-blue-50"
              >
                <User size={16} />
                {isAdmin ? 'Admin Dashboard' : 'Admin Login'}
              </button>
            </div>
          </div>

          {/* Mobile menu button */}
          <div className="md:hidden">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className="p-2 rounded-md hover:bg-blue-700 focus:outline-none"
            >
              {isOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Nav */}
      {isOpen && (
        <div className="md:hidden bg-blue-900 px-2 pt-2 pb-3 space-y-1 sm:px-3">
          {navItems.map((item) => (
            <button
              key={item.label}
              onClick={() => {
                setView(item.view);
                setIsOpen(false);
              }}
              className="block px-3 py-2 rounded-md text-base font-medium w-full text-left hover:bg-blue-800"
            >
              {item.label}
            </button>
          ))}
          <button
            onClick={() => {
              setView(isAdmin ? 'ADMIN_DASHBOARD' : 'ADMIN_LOGIN');
              setIsOpen(false);
            }}
            className="flex items-center gap-2 px-3 py-2 rounded-md text-base font-bold w-full text-left bg-white text-blue-800"
          >
            <User size={20} />
            {isAdmin ? 'Admin Dashboard' : 'Admin Login'}
          </button>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React, { useState } from 'react';
import { Notice, Service } from '../types';
import { ArrowRight, MessageCircle, Send, Loader2, Info } from 'lucide-react';
import { getHealthAdvice } from '../services/geminiService';

interface HomeProps {
  notices: Notice[];
  services: Service[];
  setView: (view: any) => void;
}

const Home: React.FC<HomeProps> = ({ notices, services, setView }) => {
  const [aiQuery, setAiQuery] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [loading, setLoading] = useState(false);

  const handleAiConsult = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!aiQuery.trim()) return;
    setLoading(true);
    const advice = await getHealthAdvice(aiQuery);
    setAiResponse(advice);
    setLoading(false);
  };

  return (
    <div className="space-y-12 pb-16">
      {/* Hero Section */}
      <section className="relative h-[500px] flex items-center justify-center overflow-hidden">
        <img 
          src="https://picsum.photos/seed/hospital-beltar/1920/1080" 
          className="absolute inset-0 w-full h-full object-cover brightness-50"
          alt="Hospital Building"
        />
        <div className="relative z-10 text-center text-white px-4 max-w-4xl">
          <h2 className="text-4xl md:text-6xl font-black mb-4">Dedicated to Your Health</h2>
          <p className="text-xl md:text-2xl mb-8 opacity-90 font-medium">Serving the community of Beltar and Chaudandigadhi with excellence and compassion.</p>
          <div className="flex flex-col sm:flex-row gap-4 justify-center">
            <button 
              onClick={() => setView('SERVICES')}
              className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-4 rounded-full font-bold text-lg transition-all transform hover:scale-105"
            >
              Explore Our Services
            </button>
            <button 
              onClick={() => document.getElementById('notices')?.scrollIntoView({ behavior: 'smooth' })}
              className="bg-white hover:bg-slate-100 text-blue-900 px-8 py-4 rounded-full font-bold text-lg transition-all"
            >
              Latest Notices
            </button>
          </div>
        </div>
      </section>

      <div className="max-w-7xl mx-auto px-4 grid grid-cols-1 lg:grid-cols-3 gap-12">
        {/* Notices Section */}
        <div id="notices" className="lg:col-span-2 space-y-6">
          <div className="flex items-center justify-between border-b-2 border-blue-100 pb-2">
            <h3 className="text-2xl font-bold text-slate-800">Latest Notices & Announcements</h3>
            <span className="text-sm font-bold text-blue-600 cursor-pointer hover:underline">View All</span>
          </div>
          <div className="grid gap-4">
            {notices.map((notice) => (
              <div key={notice.id} className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 hover:shadow-md transition-shadow">
                <div className="flex justify-between items-start mb-2">
                  <span className={`px-2 py-1 rounded text-[10px] font-black uppercase tracking-wider ${
                    notice.category === 'Emergency' ? 'bg-red-100 text-red-700' : 'bg-blue-100 text-blue-700'
                  }`}>
                    {notice.category}
                  </span>
                  <span className="text-sm text-slate-500 font-medium">{notice.date}</span>
                </div>
                <h4 className="text-lg font-bold text-slate-900 mb-2">{notice.title}</h4>
                <p className="text-slate-600 text-sm line-clamp-2">{notice.content}</p>
                <button className="mt-4 text-blue-600 font-bold text-sm flex items-center gap-1 hover:gap-2 transition-all">
                  Read Full Notice <ArrowRight size={16} />
                </button>
              </div>
            ))}
          </div>
        </div>

        {/* AI Health Assistant Sidebar */}
        <div className="space-y-6">
          <div className="bg-gradient-to-br from-blue-800 to-blue-900 rounded-2xl p-6 text-white shadow-xl">
            <div className="flex items-center gap-2 mb-4">
              <MessageCircle className="text-blue-300" />
              <h3 className="text-xl font-bold">Smart Health Assistant</h3>
            </div>
            <p className="text-sm opacity-80 mb-6 font-medium">Ask any health-related question and get instant advice from our AI assistant (English/Nepali).</p>

            <form onSubmit={handleAiConsult} className="space-y-4">
              <div className="relative">
                <textarea
                  value={aiQuery}
                  onChange={(e) => setAiQuery(e.target.value)}
                  placeholder="Example: How to prevent Dengue? (डेंगुबाट कसरी बच्ने?)"
                  className="w-full bg-blue-950/50 border border-blue-700 rounded-xl p-4 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400 placeholder:text-blue-400/50 min-h-[100px]"
                />
              </div>
              <button 
                type="submit"
                disabled={loading}
                className="w-full bg-white text-blue-900 py-3 rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-blue-50 transition-colors disabled:opacity-50"
              >
                {loading ? <Loader2 className="animate-spin" /> : <><Send size={18} /> Get Advice</>}
              </button>
            </form>

            {aiResponse && (
              <div className="mt-6 bg-blue-950/40 p-4 rounded-xl border border-blue-700/50 text-sm animate-in fade-in slide-in-from-bottom-2">
                <p className="whitespace-pre-wrap leading-relaxed">{aiResponse}</p>
                <div className="mt-4 flex items-start gap-2 text-[10px] opacity-60">
                  <Info size={14} className="shrink-0" />
                  <p>Disclaimer: This is AI-generated advice. For serious conditions, visit our emergency ward immediately.</p>
                </div>
              </div>
            )}
          </div>

          <div className="bg-white p-6 rounded-2xl border border-slate-200">
            <h4 className="font-bold text-slate-800 mb-4">Emergency Contacts</h4>
            <div className="space-y-3">
              <div className="flex justify-between items-center text-sm">
                <span className="text-slate-500">Ambulance</span>
                <span className="font-black text-blue-700">102</span>
              </div>
              <div className="flex justify-between items-center text-sm">
                <span className="text-slate-500">Reception</span>
                <span className="font-black text-blue-700">035-XXXXXX</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Home;

