import React, { useState } from 'react';
import { Notice, Service, Doctor } from '../types';
import { Plus, Trash2, Edit3, LayoutDashboard, FileText, Users, Settings, LogOut } from 'lucide-react';

interface AdminDashboardProps {
  notices: Notice[];
  services: Service[];
  doctors: Doctor[];
  onLogout: () => void;
  updateNotices: (n: Notice[]) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ notices, services, doctors, onLogout, updateNotices }) => {
  const [activeTab, setActiveTab] = useState<'notices' | 'services' | 'doctors'>('notices');
  const [isAdding, setIsAdding] = useState(false);

  // Simple Mock Add State
  const [newNotice, setNewNotice] = useState({ title: '', content: '', category: 'General' });

  const handleAddNotice = () => {
    const notice: Notice = {
      id: Math.random().toString(36).substr(2, 9),
      title: newNotice.title,
      content: newNotice.content,
      date: new Date().toISOString().split('T')[0],
      category: newNotice.category as any
    };
    updateNotices([notice, ...notices]);
    setIsAdding(false);
    setNewNotice({ title: '', content: '', category: 'General' });
  };

  const handleDeleteNotice = (id: string) => {
    updateNotices(notices.filter(n => n.id !== id));
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Sidebar */}
      <div className="w-full md:w-64 bg-slate-900 text-white flex flex-col">
        <div className="p-6 border-b border-slate-800">
          <h2 className="text-xl font-black tracking-tight">Admin Panel</h2>
          <p className="text-xs text-slate-500 mt-1 uppercase font-bold">Beltar Hospital</p>
        </div>
        <nav className="flex-1 p-4 space-y-2">
          <button 
            onClick={() => setActiveTab('notices')}
            className={`flex items-center gap-3 w-full px-4 py-3 rounded-lg text-sm font-bold transition-colors ${activeTab === 'notices' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
          >
            <FileText size={18} /> Manage Notices
          </button>
          <button 
            onClick={() => setActiveTab('services')}
            className={`flex items-center gap-3 w-full px-4 py-3 rounded-lg text-sm font-bold transition-colors ${activeTab === 'services' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
          >
            <LayoutDashboard size={18} /> Manage Services
          </button>
          <button 
            onClick={() => setActiveTab('doctors')}
            className={`flex items-center gap-3 w-full px-4 py-3 rounded-lg text-sm font-bold transition-colors ${activeTab === 'doctors' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
          >
            <Users size={18} /> Manage Doctors
          </button>
          <div className="pt-4 mt-4 border-t border-slate-800">
            <button 
              onClick={onLogout}
              className="flex items-center gap-3 w-full px-4 py-3 rounded-lg text-sm font-bold text-red-400 hover:bg-red-500/10 transition-colors"
            >
              <LogOut size={18} /> Logout
            </button>
          </div>
        </nav>
      </div>

      {/* Main Content */}
      <div className="flex-1 p-8 overflow-y-auto">
        <div className="flex justify-between items-center mb-8">
          <h3 className="text-2xl font-black text-slate-900 capitalize">Manage {activeTab}</h3>
          <button 
            onClick={() => setIsAdding(true)}
            className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-bold flex items-center gap-2 shadow-sm"
          >
            <Plus size={18} /> Add New
          </button>
        </div>

        {isAdding && activeTab === 'notices' && (
          <div className="bg-white p-6 rounded-2xl shadow-lg border border-blue-100 mb-8 animate-in fade-in slide-in-from-top-4">
            <h4 className="text-lg font-bold mb-4">Add New Notice</h4>
            <div className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Title</label>
                <input 
                  type="text" 
                  value={newNotice.title}
                  onChange={(e) => setNewNotice({...newNotice, title: e.target.value})}
                  className="w-full border border-slate-200 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none" 
                  placeholder="Enter notice title"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Category</label>
                  <select 
                    value={newNotice.category}
                    onChange={(e) => setNewNotice({...newNotice, category: e.target.value})}
                    className="w-full border border-slate-200 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                  >
                    <option>General</option>
                    <option>Emergency</option>
                    <option>Vaccination</option>
                    <option>Career</option>
                  </select>
                </div>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Content</label>
                <textarea 
                   value={newNotice.content}
                   onChange={(e) => setNewNotice({...newNotice, content: e.target.value})}
                   className="w-full border border-slate-200 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none min-h-[100px]" 
                   placeholder="Enter detailed content..."
                />
              </div>
              <div className="flex gap-2">
                <button onClick={handleAddNotice} className="bg-blue-600 text-white px-6 py-2 rounded-lg font-bold">Save Notice</button>
                <button onClick={() => setIsAdding(false)} className="bg-slate-100 text-slate-600 px-6 py-2 rounded-lg font-bold">Cancel</button>
              </div>
            </div>
          </div>
        )}

        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-xs font-black uppercase tracking-wider">
              <tr>
                <th className="px-6 py-4">Title / Info</th>
                <th className="px-6 py-4">Status / Category</th>
                <th className="px-6 py-4">Date Added</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {activeTab === 'notices' && notices.map((notice) => (
                <tr key={notice.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-900">{notice.title}</div>
                    <div className="text-xs text-slate-400 truncate max-w-xs">{notice.content}</div>
                  </td>
                  <td className="px-6 py-4">
                    <span className="bg-blue-100 text-blue-700 px-2 py-1 rounded-full text-[10px] font-black uppercase tracking-tighter">
                      {notice.category}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-500">{notice.date}</td>
                  <td className="px-6 py-4 text-right space-x-2">
                    <button className="p-2 text-slate-400 hover:text-blue-600 transition-colors"><Edit3 size={18} /></button>
                    <button onClick={() => handleDeleteNotice(notice.id)} className="p-2 text-slate-400 hover:text-red-600 transition-colors"><Trash2 size={18} /></button>
                  </td>
                </tr>
              ))}
              {/* Similar loops for services and doctors would go here */}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import { ViewState, Notice, Service, Doctor } from './types';
import { INITIAL_NOTICES, INITIAL_SERVICES, INITIAL_DOCTORS } from './constants';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import Home from './pages/Home';
import Services from './pages/Services';
import AdminDashboard from './pages/AdminDashboard';
import { LogIn, ShieldCheck, AlertCircle } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('HOME');
  const [isAdmin, setIsAdmin] = useState(false);
  const [notices, setNotices] = useState<Notice[]>(INITIAL_NOTICES);
  const [services] = useState<Service[]>(INITIAL_SERVICES);
  const [doctors] = useState<Doctor[]>(INITIAL_DOCTORS);

  // Simple Admin Login State
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [loginError, setLoginError] = useState('');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (loginData.username === 'admin' && loginData.password === 'beltar123') {
      setIsAdmin(true);
      setView('ADMIN_DASHBOARD');
      setLoginError('');
    } else {
      setLoginError('Invalid credentials. Please contact system administrator.');
    }
  };

  const handleLogout = () => {
    setIsAdmin(false);
    setView('HOME');
  };

  // Content Renderer
  const renderContent = () => {
    switch (view) {
      case 'HOME':
        return <Home notices={notices} services={services} setView={setView} />;
      case 'SERVICES':
        return <Services services={services} />;
      case 'DOCTORS':
        return (
          <div className="max-w-7xl mx-auto px-4 py-16">
            <h2 className="text-3xl font-black mb-8 text-center">Our Medical Staff</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              {doctors.map(doc => (
                <div key={doc.id} className="bg-white rounded-3xl overflow-hidden border border-slate-100 shadow-sm hover:shadow-lg transition-all">
                  <img src={doc.image} alt={doc.name} className="w-full h-64 object-cover" />
                  <div className="p-6">
                    <h3 className="text-xl font-bold mb-1">{doc.name}</h3>
                    <p className="text-blue-600 font-bold text-sm mb-4">{doc.specialization}</p>
                    <div className="flex justify-between items-center text-xs text-slate-500 font-medium">
                      <span>Available:</span>
                      <span className="text-slate-900 font-bold">{doc.availability}</span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'ABOUT':
        return (
          <div className="max-w-4xl mx-auto px-4 py-16 space-y-8">
             <h2 className="text-4xl font-black text-slate-900">About Beltar Municipal Hospital</h2>
             <div className="prose prose-blue lg:prose-lg max-w-none text-slate-600 font-medium">
               <p>Aadharbhut Nagar Aspatal Beltar is a primary healthcare facility established to provide quality medical services to the residents of Chaudandigadhi Municipality, Udayapur. Our mission is to ensure that no citizen is deprived of basic health services due to geographical or financial constraints.</p>
               <h3 className="text-2xl font-bold text-slate-800 mt-8 mb-4">Our Mission</h3>
               <p>To provide accessible, high-quality, and reliable medical services through specialized human resources and modern medical technology.</p>
               <h3 className="text-2xl font-bold text-slate-800 mt-8 mb-4">Our History</h3>
               <p>The hospital was upgraded to a basic municipal hospital level in alignment with the federal government's policy of establishing at least one basic hospital in every local unit across Nepal.</p>
             </div>
          </div>
        );
      case 'ADMIN_LOGIN':
        return (
          <div className="max-w-md mx-auto py-24 px-4">
            <div className="bg-white rounded-3xl shadow-2xl overflow-hidden border border-slate-100">
              <div className="bg-blue-800 p-8 text-center text-white">
                <ShieldCheck size={48} className="mx-auto mb-4 opacity-80" />
                <h2 className="text-2xl font-black">Authorized Personnel Only</h2>
                <p className="text-sm opacity-70 mt-1">Admin Portal for Beltar Hospital</p>
              </div>
              <form onSubmit={handleLogin} className="p-8 space-y-6">
                {loginError && (
                  <div className="bg-red-50 text-red-600 p-3 rounded-lg text-xs font-bold flex items-center gap-2">
                    <AlertCircle size={16} /> {loginError}
                  </div>
                )}
                <div className="space-y-4">
                  <div>
                    <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Username</label>
                    <input 
                      type="text" 
                      required
                      value={loginData.username}
                      onChange={(e) => setLoginData({...loginData, username: e.target.value})}
                      className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Password</label>
                    <input 
                      type="password" 
                      required
                      value={loginData.password}
                      onChange={(e) => setLoginData({...loginData, password: e.target.value})}
                      className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                    />
                  </div>
                </div>
                <button 
                  type="submit"
                  className="w-full bg-blue-800 text-white py-4 rounded-xl font-black hover:bg-blue-900 transition-colors flex items-center justify-center gap-2"
                >
                  <LogIn size={20} /> Access Dashboard
                </button>
              </form>
            </div>
          </div>
        );
      case 'ADMIN_DASHBOARD':
        return (
          <AdminDashboard 
            notices={notices} 
            services={services} 
            doctors={doctors} 
            onLogout={handleLogout}
            updateNotices={setNotices}
          />
        );
      default:
        return <Home notices={notices} services={services} setView={setView} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col font-sans">
      {view !== 'ADMIN_DASHBOARD' && (
        <Navbar currentView={view} setView={setView} isAdmin={isAdmin} />
      )}

      <main className="flex-1">
        {renderContent()}
      </main>

      {view !== 'ADMIN_DASHBOARD' && <Footer />}
    </div>
  );
};

export default App;

