import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getHealthAdvice = async (query: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `You are a helpful medical assistant for Aadharbhut Nagar Aspatal (Beltar Municipal Hospital). 
      Provide concise health advice STRICTLY in Nepali language (using Devanagari script). 
      User Query: ${query}. 
      Always state that this is AI advice and they should consult a real doctor for emergencies in Nepali.`,
      config: {
        temperature: 0.7,
        topP: 0.8,
        topK: 40,
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "माफ गर्नुहोला, अहिले जडानमा समस्या भयो। कृपया हाम्रो मेडिकल अफिसरसँग सम्पर्क गर्नुहोला।";
  }
};

