import React, { useState } from 'react';
import { Notice, Service, Doctor } from '../types';
import { Plus, Trash2, Edit3, LayoutDashboard, FileText, Users, LogOut, X } from 'lucide-react';

interface AdminDashboardProps {
  notices: Notice[];
  services: Service[];
  doctors: Doctor[];
  onLogout: () => void;
  updateNotices: (n: Notice[]) => void;
  updateServices: (s: Service[]) => void;
  updateDoctors: (d: Doctor[]) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  notices, 
  services, 
  doctors, 
  onLogout, 
  updateNotices,
  updateServices,
  updateDoctors 
}) => {
  const [activeTab, setActiveTab] = useState<'notices' | 'services' | 'doctors'>('notices');
  const [isAdding, setIsAdding] = useState(false);

  // States for new items
  const [newNotice, setNewNotice] = useState({ title: '', content: '', category: 'General' });
  const [newService, setNewService] = useState({ name: '', description: '', icon: 'Stethoscope' });
  const [newDoctor, setNewDoctor] = useState({ name: '', specialization: '', availability: '', image: 'https://picsum.photos/seed/doc/400/400' });

  // Notice Handlers
  const handleAddNotice = () => {
    if (!newNotice.title || !newNotice.content) return;
    const item: Notice = {
      id: Math.random().toString(36).substr(2, 9),
      title: newNotice.title,
      content: newNotice.content,
      date: new Date().toLocaleDateString('ne-NP'),
      category: newNotice.category as any
    };
    updateNotices([item, ...notices]);
    setIsAdding(false);
    setNewNotice({ title: '', content: '', category: 'General' });
  };

  const handleDeleteNotice = (id: string) => {
    if(confirm('के तपाईं यो सूचना हटाउन चाहनुहुन्छ?')) {
      updateNotices(notices.filter(n => n.id !== id));
    }
  };

  // Service Handlers
  const handleAddService = () => {
    if (!newService.name || !newService.description) return;
    const item: Service = {
      id: Math.random().toString(36).substr(2, 9),
      name: newService.name,
      description: newService.description,
      icon: newService.icon
    };
    updateServices([...services, item]);
    setIsAdding(false);
    setNewService({ name: '', description: '', icon: 'Stethoscope' });
  };

  const handleDeleteService = (id: string) => {
    if(confirm('के तपाईं यो सेवा हटाउन चाहनुहुन्छ?')) {
      updateServices(services.filter(s => s.id !== id));
    }
  };

  // Doctor Handlers
  const handleAddDoctor = () => {
    if (!newDoctor.name || !newDoctor.specialization) return;
    const item: Doctor = {
      id: Math.random().toString(36).substr(2, 9),
      name: newDoctor.name,
      specialization: newDoctor.specialization,
      availability: newDoctor.availability || 'संपर्क गर्नुहोस्',
      image: newDoctor.image
    };
    updateDoctors([...doctors, item]);
    setIsAdding(false);
    setNewDoctor({ name: '', specialization: '', availability: '', image: 'https://picsum.photos/seed/doc/400/400' });
  };

  const handleDeleteDoctor = (id: string) => {
    if(confirm('के तपाईं यो चिकित्सक हटाउन चाहनुहुन्छ?')) {
      updateDoctors(doctors.filter(d => d.id !== id));
    }
  };

  const renderAddForm = () => {
    if (!isAdding) return null;

    return (
      <div className="bg-white p-6 rounded-2xl shadow-lg border border-blue-100 mb-8 animate-in fade-in slide-in-from-top-4">
        <div className="flex justify-between items-center mb-4">
          <h4 className="text-lg font-bold">नयाँ {activeTab === 'notices' ? 'सूचना' : activeTab === 'services' ? 'सेवा' : 'चिकित्सक'} थप्नुहोस्</h4>
          <button onClick={() => setIsAdding(false)} className="text-slate-400 hover:text-slate-600"><X size={20} /></button>
        </div>

        {activeTab === 'notices' && (
          <div className="space-y-4">
            <input type="text" placeholder="सूचनाको शीर्षक" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" value={newNotice.title} onChange={e => setNewNotice({...newNotice, title: e.target.value})} />
            <select className="w-full border p-3 rounded-xl outline-none" value={newNotice.category} onChange={e => setNewNotice({...newNotice, category: e.target.value})}>
              <option value="General">साधारण (General)</option>
              <option value="Emergency">आपतकालीन (Emergency)</option>
              <option value="Vaccination">खोप (Vaccination)</option>
              <option value="Career">वृत्ति (Career)</option>
            </select>
            <textarea placeholder="सूचनाको विवरण" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 min-h-[100px]" value={newNotice.content} onChange={e => setNewNotice({...newNotice, content: e.target.value})} />
            <button onClick={handleAddNotice} className="bg-blue-600 text-white px-6 py-3 rounded-xl font-bold w-full">सूचना सुरक्षित गर्नुहोस्</button>
          </div>
        )}

        {activeTab === 'services' && (
          <div className="space-y-4">
            <input type="text" placeholder="सेवाको नाम" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" value={newService.name} onChange={e => setNewService({...newService, name: e.target.value})} />
            <select className="w-full border p-3 rounded-xl outline-none" value={newService.icon} onChange={e => setNewService({...newService, icon: e.target.value})}>
              <option value="Stethoscope">Stethoscope (OPD)</option>
              <option value="Ambulance">Ambulance (Emergency)</option>
              <option value="Baby">Baby (Maternity)</option>
              <option value="TestTube">TestTube (Lab)</option>
              <option value="Pill">Pill (Pharmacy)</option>
              <option value="Activity">Activity (Radiology)</option>
            </select>
            <textarea placeholder="सेवाको विवरण" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 min-h-[100px]" value={newService.description} onChange={e => setNewService({...newService, description: e.target.value})} />
            <button onClick={handleAddService} className="bg-blue-600 text-white px-6 py-3 rounded-xl font-bold w-full">सेवा सुरक्षित गर्नुहोस्</button>
          </div>
        )}

        {activeTab === 'doctors' && (
          <div className="space-y-4">
            <input type="text" placeholder="चिकित्सकको नाम" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" value={newDoctor.name} onChange={e => setNewDoctor({...newDoctor, name: e.target.value})} />
            <input type="text" placeholder="विशेषज्ञता (Specialization)" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" value={newDoctor.specialization} onChange={e => setNewDoctor({...newDoctor, specialization: e.target.value})} />
            <input type="text" placeholder="उपलब्धता (समय)" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" value={newDoctor.availability} onChange={e => setNewDoctor({...newDoctor, availability: e.target.value})} />
            <input type="text" placeholder="फोटो URL (Optional)" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" value={newDoctor.image} onChange={e => setNewDoctor({...newDoctor, image: e.target.value})} />
            <button onClick={handleAddDoctor} className="bg-blue-600 text-white px-6 py-3 rounded-xl font-bold w-full">चिकित्सक सुरक्षित गर्नुहोस्</button>
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Sidebar */}
      <div className="w-full md:w-64 bg-slate-900 text-white flex flex-col">
        <div className="p-6 border-b border-slate-800">
          <h2 className="text-xl font-black tracking-tight">प्रशासन प्यानल</h2>
          <p className="text-xs text-slate-500 mt-1 uppercase font-bold">बेल्टार अस्पताल</p>
        </div>
        <nav className="flex-1 p-4 space-y-2">
          <button 
            onClick={() => {setActiveTab('notices'); setIsAdding(false);}}
            className={`flex items-center gap-3 w-full px-4 py-3 rounded-lg text-sm font-bold transition-colors ${activeTab === 'notices' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
          >
            <FileText size={18} /> सूचना व्यवस्थापन
          </button>
          <button 
            onClick={() => {setActiveTab('services'); setIsAdding(false);}}
            className={`flex items-center gap-3 w-full px-4 py-3 rounded-lg text-sm font-bold transition-colors ${activeTab === 'services' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
          >
            <LayoutDashboard size={18} /> सेवा व्यवस्थापन
          </button>
          <button 
            onClick={() => {setActiveTab('doctors'); setIsAdding(false);}}
            className={`flex items-center gap-3 w-full px-4 py-3 rounded-lg text-sm font-bold transition-colors ${activeTab === 'doctors' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
          >
            <Users size={18} /> चिकित्सक व्यवस्थापन
          </button>
          <div className="pt-4 mt-4 border-t border-slate-800">
            <button onClick={onLogout} className="flex items-center gap-3 w-full px-4 py-3 rounded-lg text-sm font-bold text-red-400 hover:bg-red-500/10 transition-colors">
              <LogOut size={18} /> लग-आउट
            </button>
          </div>
        </nav>
      </div>

      {/* Main Content */}
      <div className="flex-1 p-8 overflow-y-auto">
        <div className="flex justify-between items-center mb-8">
          <h3 className="text-2xl font-black text-slate-900">
            {activeTab === 'notices' ? 'सूचना व्यवस्थापन' : activeTab === 'services' ? 'सेवा व्यवस्थापन' : 'चिकित्सक व्यवस्थापन'}
          </h3>
          <button 
            onClick={() => setIsAdding(!isAdding)}
            className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-bold flex items-center gap-2 shadow-sm transition-all"
          >
            {isAdding ? <><X size={18} /> बन्द गर्नुहोस्</> : <><Plus size={18} /> नयाँ थप्नुहोस्</>}
          </button>
        </div>

        {renderAddForm()}

        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-xs font-black uppercase tracking-wider">
              <tr>
                <th className="px-6 py-4">नाम / शीर्षक</th>
                <th className="px-6 py-4">{activeTab === 'notices' ? 'वर्ग' : activeTab === 'services' ? 'विवरण' : 'विशेषज्ञता'}</th>
                <th className="px-6 py-4 text-right">कार्य</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {activeTab === 'notices' && notices.map((notice) => (
                <tr key={notice.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-900">{notice.title}</div>
                    <div className="text-[10px] text-slate-400">{notice.date}</div>
                  </td>
                  <td className="px-6 py-4">
                    <span className="bg-blue-100 text-blue-700 px-2 py-1 rounded-full text-[10px] font-black uppercase">
                      {notice.category}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button onClick={() => handleDeleteNotice(notice.id)} className="p-2 text-slate-400 hover:text-red-600 transition-colors"><Trash2 size={18} /></button>
                  </td>
                </tr>
              ))}

              {activeTab === 'services' && services.map((service) => (
                <tr key={service.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 font-bold text-slate-900">{service.name}</td>
                  <td className="px-6 py-4 text-sm text-slate-500 truncate max-w-xs">{service.description}</td>
                  <td className="px-6 py-4 text-right">
                    <button onClick={() => handleDeleteService(service.id)} className="p-2 text-slate-400 hover:text-red-600 transition-colors"><Trash2 size={18} /></button>
                  </td>
                </tr>
              ))}

              {activeTab === 'doctors' && doctors.map((doc) => (
                <tr key={doc.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 font-bold text-slate-900">{doc.name}</td>
                  <td className="px-6 py-4 text-sm text-slate-500">{doc.specialization}</td>
                  <td className="px-6 py-4 text-right">
                    <button onClick={() => handleDeleteDoctor(doc.id)} className="p-2 text-slate-400 hover:text-red-600 transition-colors"><Trash2 size={18} /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;

