               <h3 className="text-2xl font-bold text-slate-800 mt-8 mb-4">हाम्रो इतिहास</h3>
               <p>नेपाल सरकारको "एक स्थानीय तह, एक आधारभूत अस्पताल" नीति अनुरुप यस अस्पताललाई स्तरोन्नति गरि नगर अस्पतालको रुपमा संचालन गरिएको हो।</p>
             </div>
          </div>
        );
      case 'ADMIN_LOGIN':
        return (
          <div className="max-w-md mx-auto py-24 px-4">
            <div className="bg-white rounded-3xl shadow-2xl overflow-hidden border border-slate-100">
              <div className="bg-blue-800 p-8 text-center text-white">
                <ShieldCheck size={48} className="mx-auto mb-4 opacity-80" />
                <h2 className="text-2xl font-black">प्रशासनिक क्षेत्र</h2>
                <p className="text-sm opacity-70 mt-1">बेल्टार अस्पताल प्रशासनिक लगइन</p>
              </div>
              <form onSubmit={handleLogin} className="p-8 space-y-6">
                {loginError && (
                  <div className="bg-red-50 text-red-600 p-3 rounded-lg text-xs font-bold flex items-center gap-2">
                    <AlertCircle size={16} /> {loginError}
                  </div>
                )}
                <div className="space-y-4">
                  <div>
                    <label htmlFor="username" className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">प्रयोगकर्ताको नाम (Username)</label>
                    <input 
                      id="username"
                      name="username"
                      type="text" 
                      required
                      autoComplete="username"
                      value={username}
                      onChange={(e) => setUsername(e.target.value)}
                      className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-slate-900 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                      placeholder="Username लेख्नुहोस्"
                    />
                  </div>
                  <div>
                    <label htmlFor="password" className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">पासवर्ड (Password)</label>
                    <input 
                      id="password"
                      name="password"
                      type="password" 
                      required
                      autoComplete="current-password"
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-slate-900 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                      placeholder="Password लेख्नुहोस्"
                    />
                  </div>
                </div>
                <button 
                  type="submit"
                  className="w-full bg-blue-800 text-white py-4 rounded-xl font-black hover:bg-blue-900 transition-colors flex items-center justify-center gap-2"
                >
                  <LogIn size={20} /> लग-इन गर्नुहोस्
                </button>
              </form>
            </div>
          </div>
        );
      case 'ADMIN_DASHBOARD':
        return (
          <AdminDashboard 
            notices={notices} 
            services={services} 
            doctors={doctors} 
            onLogout={handleLogout}
            updateNotices={setNotices}
            updateServices={setServices}
            updateDoctors={setDoctors}
          />
        );
      default:
        return <Home notices={notices} services={services} setView={setView} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col font-sans">
      {view !== 'ADMIN_DASHBOARD' && (
        <Navbar currentView={view} setView={setView} isAdmin={isAdmin} />
      )}

      <main className="flex-1">
        {renderContent()}
      </main>

      {view !== 'ADMIN_DASHBOARD' && <Footer />}
    </div>
  );
};

