import { LogIn as LogInIcon, ShieldCheck as ShieldIcon, AlertCircle as AlertIcon } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('HOME');
  const [isAdmin, setIsAdmin] = useState(false);
  const [notices, setNotices] = useState<Notice[]>(INITIAL_NOTICES);
  const [services, setServices] = useState<Service[]>(INITIAL_SERVICES);
  const [doctors, setDoctors] = useState<Doctor[]>(INITIAL_DOCTORS);

  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (username === 'admin' && password === 'beltar123') {
      setIsAdmin(true);
      setView('ADMIN_DASHBOARD');
      setLoginError('');
      setUsername('');
      setPassword('');
    } else {
      setLoginError('गलत विवरण। कृपया प्रशासन शाखामा सम्पर्क गर्नुहोस्।');
    }
  };

  const handleLogout = () => {
    setIsAdmin(false);
    setView('HOME');
  };

  const renderContent = () => {
    switch (view) {
      case 'HOME':
        return <Home notices={notices} services={services} setView={setView} />;
      case 'NOTICES':
        return <Notices notices={notices} />;
      case 'SERVICES':
        return <Services services={services} />;
      case 'DOCTORS':
        return (
          <div className="max-w-7xl mx-auto px-4 py-16">
            <h2 className="text-3xl font-black mb-8 text-center text-slate-900">हाम्रा कर्मचारीहरू</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              {doctors.map(doc => (
                <div key={doc.id} className="bg-white rounded-3xl overflow-hidden border border-slate-100 shadow-sm hover:shadow-lg transition-all">
                  <img src={doc.image} alt={doc.name} className="w-full h-64 object-cover" />
                  <div className="p-6">
                    <h3 className="text-xl font-bold mb-1 text-slate-900">{doc.name}</h3>
                    <p className="text-blue-600 font-bold text-sm mb-4">{doc.specialization}</p>
                    <div className="flex justify-between items-center text-xs text-slate-500 font-medium">
                      <span>उपलब्धता:</span>
                      <span className="text-slate-900 font-bold">{doc.availability}</span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'ABOUT':
        return (
          <div className="max-w-4xl mx-auto px-4 py-16 space-y-8">
             <h2 className="text-4xl font-black text-slate-900">बेल्टार आधारभूत नगर अस्पतालको बारेमा</h2>
             <div className="prose prose-blue lg:prose-lg max-w-none text-slate-600 font-medium leading-relaxed">
               <p>आधारभूत नगर अस्पताल बेल्टार, चौदण्डीगढी नगरपालिका, उदयपुरको एक प्रमुख स्वास्थ्य संस्था हो। यस अस्पतालको मुख्य लक्ष्य स्थानीय बासिन्दाहरूलाई सुलभ, गुणस्तरीय र प्रभावकारी स्वास्थ्य सेवा प्रदान गर्नु हो।</p>
               <h3 className="text-2xl font-bold text-slate-800 mt-8 mb-4">हाम्रो लक्ष्य</h3>
               <p>आधुनिक चिकित्सा प्रविधि र दक्ष जनशक्तिको माध्यमबाट समाजका हरेक वर्गलाई आधारभूत स्वास्थ्य सेवाको पहुँचमा पुर्याउनु नै हाम्रो मुख्य लक्ष्य हो।</p>
               <h3 className="text-2xl font-bold text-slate-800 mt-8 mb-4">हाम्रो इतिहास</h3>
               <p>नेपाल सरकारको "एक स्थानीय तह, एक आधारभूत अस्पताल" नीति अनुरुप यस अस्पताललाई स्तरोन्नति गरि नगर अस्पतालको रुपमा संचालन गरिएको हो।</p>
             </div>
          </div>
        );
      case 'ADMIN_LOGIN':
        return (
          <div className="max-w-md mx-auto py-24 px-4">
            <div className="bg-white rounded-3xl shadow-2xl overflow-hidden border border-slate-100">
              <div className="bg-blue-800 p-8 text-center text-white">
                <ShieldIcon size={48} className="mx-auto mb-4 opacity-80" />
                <h2 className="text-2xl font-black">प्रशासनिक क्षेत्र</h2>
                <p className="text-sm opacity-70 mt-1">बेल्टार अस्पताल प्रशासनिक लगइन</p>
              </div>
              <form onSubmit={handleLogin} className="p-8 space-y-6">
                {loginError && (
                  <div className="bg-red-50 text-red-600 p-3 rounded-lg text-xs font-bold flex items-center gap-2">
                    <AlertIcon size={16} /> {loginError}
                  </div>
                )}
                <div className="space-y-4">
                  <div>
                    <label htmlFor="username" className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">प्रयोगकर्ताको नाम (Username)</label>
                    <input 
                      id="username"
                      name="username"
                      type="text" 
                      required
                      autoComplete="username"
                      value={username}
                      onChange={(e) => setUsername(e.target.value)}
                      className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-slate-900 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                      placeholder="Username लेख्नुहोस्"
                    />
                  </div>
                  <div>
                    <label htmlFor="password" className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">पासवर्ड (Password)</label>
                    <input 
                      id="password"
                      name="password"
                      type="password" 
                      required
                      autoComplete="current-password"
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-slate-900 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                      placeholder="Password लेख्नुहोस्"
                    />
                  </div>
                </div>
                <button 
                  type="submit"
                  className="w-full bg-blue-800 text-white py-4 rounded-xl font-black hover:bg-blue-900 transition-colors flex items-center justify-center gap-2"
                >
                  <LogInIcon size={20} /> लग-इन गर्नुहोस्
                </button>
              </form>
            </div>
          </div>
        );
      case 'ADMIN_DASHBOARD':
        return (
          <AdminDashboard 
            notices={notices} 
            services={services} 
            doctors={doctors} 
            onLogout={handleLogout}
            updateNotices={setNotices}
            updateServices={setServices}
            updateDoctors={setDoctors}
          />
        );
      default:
        return <Home notices={notices} services={services} setView={setView} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col font-sans">
      {view !== 'ADMIN_DASHBOARD' && (
        <Navbar currentView={view} setView={setView} isAdmin={isAdmin} />
      )}

      <main className="flex-1">
        {renderContent()}
      </main>

      {view !== 'ADMIN_DASHBOARD' && <Footer />}
    </div>
  );
};

export default App;

