  const [isOpen, setIsOpen] = useState(false);
  const [currentTime, setCurrentTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  // Simplified Nepali Date Logic for Year 2081 BS
  // Reference: 2024-04-13 is 2081-01-01 (Baisakh 1)
  const getNepaliDate = (date: Date) => {
    const nepaliMonths = [
      "बैशाख", "जेठ", "असार", "साउन", "भदौ", "असोज", 
      "कात्तिक", "मंसिर", "पुष", "माघ", "फागुन", "चैत"
    ];
    const nepaliDays = [
      "आइतबार", "सोमबार", "मंगलबार", "बुधबार", "बिहीबार", "शुक्रबार", "शनिबार"
    ];

    // Days in each month for BS 2081 (Reference for current year)
    const daysInMonths2081 = [31, 31, 32, 32, 31, 30, 30, 29, 30, 29, 30, 30];

    const refDate = new Date("2024-04-13");
    const diffTime = date.getTime() - refDate.getTime();
    const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));

    let year = 2081;
    let monthIndex = 0;
    let day = diffDays + 1;

    // Adjust if date is before 2081-01-01 (Fall back to simple display for safety)
    if (diffDays < 0) return `वि.सं. २०८० अन्त, ${nepaliDays[date.getDay()]}`;

    while (day > daysInMonths2081[monthIndex]) {
      day -= daysInMonths2081[monthIndex];
      monthIndex++;
      if (monthIndex > 11) {
        monthIndex = 0;
        year++;
      }
    }

    const dayName = nepaliDays[date.getDay()];
    const timeString = date.toLocaleTimeString('ne-NP', { hour12: false });

    // Convert numbers to Nepali numerals
    const toNepaliNumerals = (num: number | string) => {
      const nepaliNums = ['०', '१', '२', '३', '४', '५', '६', '७', '८', '९'];
      return num.toString().split('').map(d => nepaliNums[parseInt(d)] || d).join('');
    };

    return `वि.सं. ${toNepaliNumerals(year)} ${nepaliMonths[monthIndex]} ${toNepaliNumerals(day)} गते ${dayName}, ${timeString}`;
  };

  const formattedDate = getNepaliDate(currentTime);

