              className="h-16 w-auto drop-shadow-xl"
            />
            <div className="flex flex-col">
              <span className="text-sm font-medium opacity-90 leading-tight">चौदण्डीगढी नगरपालिका</span>
              <h1 className="text-xl md:text-2xl font-black leading-tight tracking-wide">आधारभूत नगर अस्पताल</h1>
              <span className="text-sm font-bold opacity-80">बेल्टार, उदयपुर, कोशी प्रदेश</span>
            </div>
          </div>

          {/* Center Scrolling Important Notice */}
          <div className="hidden lg:flex flex-1 mx-8 bg-blue-950/40 rounded-lg p-2 items-center overflow-hidden border border-white/5">
            <span className="bg-red-600 text-white text-[10px] font-black px-2 py-1 rounded mr-3 whitespace-nowrap animate-pulse relative z-10">महत्त्वपूर्ण सूचना |</span>
            <div className="overflow-hidden relative w-full h-6">
              <p className="absolute whitespace-nowrap text-sm font-medium animate-marquee hover:pause">
                सूचना: अस्पतालमा नयाँ डिजिटल एक्सरे मेसिन जडान गरिएको छ। जेष्ठ नागरिकहरुका लागि नि:शुल्क स्वास्थ्य शिविर यही शुक्रबार आयोजना हुँदैछ। सुत्केरी सेवा अब २४ सै घण्टा उपलब्ध छ।
              </p>
