import React, { useState, useRef } from 'react';
import { Notice, Service, Doctor, TestRate } from '../types';
import { Plus, Trash2, LayoutDashboard, FileText, Users, LogOut, X, UploadCloud, Image as ImageIcon, ClipboardList, ListPlus, Link as LinkIcon, Building2, UserCircle } from 'lucide-react';

interface AdminDashboardProps {
  notices: Notice[];
  services: Service[];
  doctors: Doctor[];
  onLogout: () => void;
  updateNotices: (n: Notice[]) => void;
  updateServices: (s: Service[]) => void;
  updateDoctors: (d: Doctor[]) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  notices, 
  services, 
  doctors, 
  onLogout, 
  updateNotices,
  updateServices,
  updateDoctors 
}) => {
  const [activeTab, setActiveTab] = useState<'notices' | 'services' | 'doctors'>('notices');
  const [isAdding, setIsAdding] = useState(false);
  const [managingRatesFor, setManagingRatesFor] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // States for new items
  const [newNotice, setNewNotice] = useState({ title: '', content: '', category: 'General', pdfUrl: '' });
  const [newService, setNewService] = useState({ name: '', description: '', icon: 'Stethoscope' });
  const [newDoctor, setNewDoctor] = useState({ name: '', specialization: '', level: '', department: '', availability: '', image: '', category: 'STAFF' });

  // State for new test rate
  const [newRate, setNewRate] = useState({ testName: '', price: '' });

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewDoctor({ ...newDoctor, image: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const triggerFileInput = () => {
    fileInputRef.current?.click();
  };

  // Notice Handlers
  const handleAddNotice = () => {
    if (!newNotice.title || !newNotice.content) return;
    const item: Notice = {
      id: Math.random().toString(36).substr(2, 9),
      title: newNotice.title,
      content: newNotice.content,
      date: new Date().toLocaleDateString('ne-NP'),
      category: newNotice.category as any,
      pdfUrl: newNotice.pdfUrl.trim() || undefined
    };
    updateNotices([item, ...notices]);
    setIsAdding(false);
    setNewNotice({ title: '', content: '', category: 'General', pdfUrl: '' });
  };

  const handleDeleteNotice = (id: string) => {
    if(confirm('के तपाईं यो सूचना हटाउन चाहनुहुन्छ?')) {
      updateNotices(notices.filter(n => n.id !== id));
    }
  };

  // Service Handlers
  const handleAddService = () => {
    if (!newService.name || !newService.description) return;
    const item: Service = {
      id: Math.random().toString(36).substr(2, 9),
      name: newService.name,
      description: newService.description,
      icon: newService.icon,
      testRates: []
    };
    updateServices([...services, item]);
    setIsAdding(false);
    setNewService({ name: '', description: '', icon: 'Stethoscope' });
  };

  const handleDeleteService = (id: string) => {
    if(confirm('के तपाईं यो सेवा हटाउन चाहनुहुन्छ?')) {
      updateServices(services.filter(s => s.id !== id));
    }
  };

  // Rate Handlers
  const handleAddRate = (serviceId: string) => {
    if (!newRate.testName || !newRate.price) return;

    const updatedServices = services.map(s => {
      if (s.id === serviceId) {
        const rates = s.testRates || [];
        return { ...s, testRates: [...rates, { ...newRate }] };
      }
      return s;
    });

    updateServices(updatedServices);
    setNewRate({ testName: '', price: '' });
  };

  const handleDeleteRate = (serviceId: string, rateIndex: number) => {
    const updatedServices = services.map(s => {
      if (s.id === serviceId && s.testRates) {
        const filteredRates = s.testRates.filter((_, idx) => idx !== rateIndex);
        return { ...s, testRates: filteredRates };
      }
      return s;
    });
    updateServices(updatedServices);
  };

  // Doctor Handlers
  const handleAddDoctor = () => {
    if (!newDoctor.name || !newDoctor.specialization) return;
    const item: Doctor = {
      id: Math.random().toString(36).substr(2, 9),
      name: newDoctor.name,
      specialization: newDoctor.specialization,
      level: newDoctor.level,
      department: newDoctor.department,
      availability: newDoctor.availability || 'संपर्क गर्नुहोस्',
      image: newDoctor.image || 'https://picsum.photos/seed/doc/400/400',
      category: newDoctor.category as any
    };
    updateDoctors([...doctors, item]);
    setIsAdding(false);
    setNewDoctor({ name: '', specialization: '', level: '', department: '', availability: '', image: '', category: 'STAFF' });
  };

  const handleDeleteDoctor = (id: string) => {
    if(confirm('के तपाईं यो कर्मचारीलाई हटाउन चाहनुहुन्छ? यो कार्य फिर्ता लिन सकिने छैन।')) {
      updateDoctors(doctors.filter(d => d.id !== id));
    }
  };

  const renderAddForm = () => {
    if (!isAdding) return null;

    return (
      <div className="bg-white p-6 rounded-2xl shadow-lg border border-blue-100 mb-8 animate-in fade-in slide-in-from-top-4">
        <div className="flex justify-between items-center mb-4">
          <h4 className="text-lg font-bold">नयाँ {activeTab === 'notices' ? 'सूचना' : activeTab === 'services' ? 'सेवा' : 'कर्मचारी'} थप्नुहोस्</h4>
          <button onClick={() => setIsAdding(false)} className="text-slate-400 hover:text-slate-600"><X size={20} /></button>
        </div>

        {activeTab === 'notices' && (
          <div className="space-y-4">
            <input type="text" placeholder="सूचनाको शीर्षक" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold" value={newNotice.title} onChange={e => setNewNotice({...newNotice, title: e.target.value})} />
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <select className="w-full border p-3 rounded-xl outline-none" value={newNotice.category} onChange={e => setNewNotice({...newNotice, category: e.target.value})}>
                <option value="General">साधारण (General)</option>
                <option value="Emergency">आपतकालीन (Emergency)</option>
                <option value="Vaccination">खोप (Vaccination)</option>
                <option value="Career">वृत्ति (Career)</option>
              </select>
              <div className="relative">
                <input 
                  type="text" 
                  placeholder="PDF लिङ्क (ऐच्छिक)" 
                  className="w-full border p-3 pl-10 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 text-sm" 
                  value={newNotice.pdfUrl} 
                  onChange={e => setNewNotice({...newNotice, pdfUrl: e.target.value})} 
                />
                <LinkIcon className="absolute left-3 top-3.5 text-slate-400" size={16} />
              </div>
            </div>
            <textarea placeholder="सूचनाको विवरण" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 min-h-[100px]" value={newNotice.content} onChange={e => setNewNotice({...newNotice, content: e.target.value})} />
            <button onClick={handleAddNotice} className="bg-blue-600 text-white px-6 py-3 rounded-xl font-bold w-full shadow-md hover:bg-blue-700 transition-colors">सूचना सुरक्षित गर्नुहोस्</button>
          </div>
        )}

        {activeTab === 'services' && (
          <div className="space-y-4">
            <input type="text" placeholder="सेवाको नाम" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" value={newService.name} onChange={e => setNewService({...newService, name: e.target.value})} />
            <select className="w-full border p-3 rounded-xl outline-none" value={newService.icon} onChange={e => setNewService({...newService, icon: e.target.value})}>
              <option value="Stethoscope">Stethoscope (OPD)</option>
              <option value="Ambulance">Ambulance (Emergency)</option>
              <option value="Baby">Baby (Maternity)</option>
              <option value="TestTube">TestTube (Lab)</option>
              <option value="Pill">Pill (Pharmacy)</option>
              <option value="Activity">Activity (Radiology)</option>
            </select>
            <textarea placeholder="सेवाको विवरण" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 min-h-[100px]" value={newService.description} onChange={e => setNewService({...newService, description: e.target.value})} />
            <button onClick={handleAddService} className="bg-blue-600 text-white px-6 py-3 rounded-xl font-bold w-full">सेवा सुरक्षित गर्नुहोस्</button>
          </div>
        )}

        {activeTab === 'doctors' && (
          <div className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
               <input type="text" placeholder="कर्मचारीको नाम" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold" value={newDoctor.name} onChange={e => setNewDoctor({...newDoctor, name: e.target.value})} />
               <select className="w-full border p-3 rounded-xl outline-none" value={newDoctor.category} onChange={e => setNewDoctor({...newDoctor, category: e.target.value})}>
                 <option value="STAFF">हाल कार्यरत कर्मचारी</option>
                 <option value="CHIEF">प्रमुखहरू</option>
                 <option value="COMMITTEE">व्यवस्थापन समिति</option>
                 <option value="FORMER">पूर्व कर्मचारी</option>
               </select>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <input type="text" placeholder="पद (Position)" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" value={newDoctor.specialization} onChange={e => setNewDoctor({...newDoctor, specialization: e.target.value})} />
              <input type="text" placeholder="तह (Level)" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" value={newDoctor.level} onChange={e => setNewDoctor({...newDoctor, level: e.target.value})} />
              <input type="text" placeholder="शाखा (Department)" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" value={newDoctor.department} onChange={e => setNewDoctor({...newDoctor, department: e.target.value})} />
            </div>

            <input type="text" placeholder="उपलब्धता (समय)" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" value={newDoctor.availability} onChange={e => setNewDoctor({...newDoctor, availability: e.target.value})} />

            <div className="flex flex-col items-center justify-center p-6 border-2 border-dashed border-slate-200 rounded-2xl hover:border-blue-400 transition-colors bg-slate-50 cursor-pointer group" onClick={triggerFileInput}>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleImageUpload} 
                className="hidden" 
                accept="image/*"
              />

              {newDoctor.image ? (
                <div className="relative">
                  <img src={newDoctor.image} alt="Preview" className="w-32 h-32 object-cover rounded-full border-4 border-white shadow-md" />
                  <div className="absolute inset-0 bg-black/20 rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                    <ImageIcon className="text-white" />
                  </div>
                </div>
              ) : (
                <>
                  <UploadCloud size={32} className="text-slate-400 group-hover:text-blue-500 mb-2" />
                  <p className="text-sm font-bold text-slate-500 group-hover:text-blue-600">फोटो अपलोड गर्नुहोस् (PC बाट)</p>
                  <p className="text-[10px] text-slate-400 uppercase tracking-wider mt-1">PNG, JPG or JPEG</p>
                </>
              )}
            </div>

            <button onClick={handleAddDoctor} className="bg-blue-600 text-white px-6 py-3 rounded-xl font-bold w-full shadow-lg">कर्मचारी विवरण सुरक्षित गर्नुहोस्</button>
          </div>
        )}
      </div>
    );
  };

  const renderRateManager = () => {
    const service = services.find(s => s.id === managingRatesFor);
    if (!service) return null;

    return (
      <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
        <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
          <div className="bg-slate-900 p-6 text-white flex justify-between items-center">
            <div>
              <h3 className="text-xl font-bold">{service.name} - दर रेट व्यवस्थापन</h3>
              <p className="text-xs text-slate-400 uppercase font-black mt-1">जाँच र शुल्क अपडेट गर्नुहोस्</p>
            </div>
            <button onClick={() => setManagingRatesFor(null)} className="p-2 hover:bg-white/10 rounded-full"><X size={24} /></button>
          </div>

          <div className="p-6 bg-slate-50 border-b border-slate-200">
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-4">
              <input 
                type="text" 
                placeholder="जाँचको नाम (उदा: Blood Sugar)" 
                className="border p-3 rounded-xl text-sm outline-none focus:ring-2 focus:ring-blue-500"
                value={newRate.testName}
                onChange={e => setNewRate({...newRate, testName: e.target.value})}
              />
              <input 
                type="text" 
                placeholder="दर (उदा: रु १००)" 
                className="border p-3 rounded-xl text-sm outline-none focus:ring-2 focus:ring-blue-500"
                value={newRate.price}
                onChange={e => setNewRate({...newRate, price: e.target.value})}
              />
            </div>
            <button 
              onClick={() => handleAddRate(service.id)}
              className="w-full bg-blue-600 text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-blue-700 transition-colors"
            >
              <ListPlus size={18} /> नयाँ दर थप्नुहोस्
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-6">
            <table className="w-full">
              <thead>
                <tr className="text-xs font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                  <th className="px-4 py-2 text-left">जाँचको नाम</th>
                  <th className="px-4 py-2 text-right">दर</th>
                  <th className="px-4 py-2 text-right">कार्य</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {service.testRates?.map((rate, idx) => (
                  <tr key={idx} className="hover:bg-slate-50">
                    <td className="px-4 py-4 text-sm font-bold text-slate-800">{rate.testName}</td>
                    <td className="px-4 py-4 text-sm font-black text-blue-700 text-right">{rate.price}</td>
                    <td className="px-4 py-4 text-right">
                      <button 
                        onClick={() => handleDeleteRate(service.id, idx)}
                        className="text-slate-400 hover:text-red-600 p-2"
                      >
                        <Trash2 size={16} />
                      </button>
                    </td>
                  </tr>
                ))}
                {(!service.testRates || service.testRates.length === 0) && (
                  <tr>
                    <td colSpan={3} className="py-8 text-center text-slate-400 italic text-sm">अहिले कुनै दर रेट थपिएको छैन।</td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>

          <div className="p-6 bg-slate-50 border-t border-slate-200 text-right">
            <button onClick={() => setManagingRatesFor(null)} className="bg-slate-900 text-white px-8 py-3 rounded-xl font-bold">बन्द गर्नुहोस्</button>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Sidebar */}
      <div className="w-full md:w-64 bg-slate-900 text-white flex flex-col">
        <div className="p-6 border-b border-slate-800">
          <h2 className="text-xl font-black tracking-tight">प्रशासन प्यानल</h2>
          <p className="text-xs text-slate-500 mt-1 uppercase font-bold">बेल्टार अस्पताल</p>
        </div>
        <nav className="flex-1 p-4 space-y-2">
          <button 
            onClick={() => {setActiveTab('notices'); setIsAdding(false);}}
            className={`flex items-center gap-3 w-full px-4 py-3 rounded-lg text-sm font-bold transition-colors ${activeTab === 'notices' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
          >
            <FileText size={18} /> सूचना व्यवस्थापन
          </button>
          <button 
            onClick={() => {setActiveTab('services'); setIsAdding(false);}}
            className={`flex items-center gap-3 w-full px-4 py-3 rounded-lg text-sm font-bold transition-colors ${activeTab === 'services' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
          >
            <LayoutDashboard size={18} /> सेवा व्यवस्थापन
          </button>
          <button 
            onClick={() => {setActiveTab('doctors'); setIsAdding(false);}}
            className={`flex items-center gap-3 w-full px-4 py-3 rounded-lg text-sm font-bold transition-colors ${activeTab === 'doctors' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
          >
            <Users size={18} /> कर्मचारी व्यवस्थापन
          </button>
          <div className="pt-4 mt-4 border-t border-slate-800">
            <button onClick={onLogout} className="flex items-center gap-3 w-full px-4 py-3 rounded-lg text-sm font-bold text-red-400 hover:bg-red-500/10 transition-colors">
              <LogOut size={18} /> लग-आउट
            </button>
          </div>
        </nav>
      </div>

      {/* Main Content */}
      <div className="flex-1 p-8 overflow-y-auto">
        <div className="flex justify-between items-center mb-8">
          <h3 className="text-2xl font-black text-slate-900">
            {activeTab === 'notices' ? 'सूचना व्यवस्थापन' : activeTab === 'services' ? 'सेवा व्यवस्थापन' : 'कर्मचारी व्यवस्थापन'}
          </h3>
          <button 
            onClick={() => setIsAdding(!isAdding)}
            className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-bold flex items-center gap-2 shadow-sm transition-all"
          >
            {isAdding ? <><X size={18} /> बन्द गर्नुहोस्</> : <><Plus size={18} /> नयाँ थप्नुहोस्</>}
          </button>
        </div>

        {renderAddForm()}
        {managingRatesFor && renderRateManager()}

        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-xs font-black uppercase tracking-wider">
              <tr>
                <th className="px-6 py-4">{activeTab === 'doctors' ? 'फोटो' : 'शिर्षक / नाम'}</th>
                {activeTab !== 'doctors' && <th className="px-6 py-4">वर्ग / विवरण</th>}
                {activeTab === 'doctors' && <th className="px-6 py-4">नाम</th>}
                {activeTab === 'doctors' && <th className="px-6 py-4">विवरण</th>}
                <th className="px-6 py-4 text-right">कार्य</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {activeTab === 'notices' && notices.map((notice) => (
                <tr key={notice.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-900">{notice.title}</div>
                    <div className="text-[10px] text-slate-400 flex items-center gap-2">
                      {notice.date} {notice.pdfUrl && <span className="bg-orange-100 text-orange-700 px-1 rounded text-[8px] font-black">PDF</span>}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <span className={`px-2 py-1 rounded-full text-[10px] font-black uppercase ${
                      notice.category === 'Emergency' ? 'bg-red-100 text-red-700' : 
                      notice.category === 'Vaccination' ? 'bg-green-100 text-green-700' :
                      'bg-blue-100 text-blue-700'
                    }`}>
                      {notice.category}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button onClick={() => handleDeleteNotice(notice.id)} className="p-2 text-slate-400 hover:text-red-600 transition-colors" title="हटाउनुहोस्"><Trash2 size={18} /></button>
                  </td>
                </tr>
              ))}

              {activeTab === 'services' && services.map((service) => (
                <tr key={service.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 font-bold text-slate-900">{service.name}</td>
                  <td className="px-6 py-4 text-sm text-slate-500 truncate max-w-xs">{service.description}</td>
                  <td className="px-6 py-4 text-right flex items-center justify-end gap-2">
                    <button 
                      onClick={() => setManagingRatesFor(service.id)}
                      className="bg-blue-50 text-blue-600 px-3 py-1.5 rounded-lg text-xs font-bold flex items-center gap-1 hover:bg-blue-100 transition-colors"
                    >
                      <ClipboardList size={14} /> दर रेट
                    </button>
                    <button onClick={() => handleDeleteService(service.id)} className="p-2 text-slate-400 hover:text-red-600 transition-colors" title="हटाउनुहोस्"><Trash2 size={18} /></button>
                  </td>
                </tr>
              ))}

              {activeTab === 'doctors' && doctors.map((doc) => (
                <tr key={doc.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <img src={doc.image} alt={doc.name} className="w-10 h-10 rounded-full object-cover border border-slate-200" />
                  </td>
                  <td className="px-6 py-4">
                    <p className="font-bold text-slate-900">{doc.name}</p>
                    <p className="text-[10px] text-blue-600 font-black uppercase tracking-wider">{doc.category}</p>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2 text-xs font-bold text-slate-700">
                      <Briefcase size={12} className="text-slate-400" /> {doc.specialization}
                    </div>
                    <div className="flex items-center gap-2 text-[10px] text-slate-500 mt-1">
                      <Layers size={10} /> तह: {doc.level} | <Building2 size={10} /> शाखा: {doc.department}
                    </div>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button onClick={() => handleDeleteDoctor(doc.id)} className="p-2 text-slate-400 hover:text-red-600 transition-colors" title="हटाउनुहोस्"><Trash2 size={18} /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {(activeTab === 'doctors' && doctors.length === 0) && (
            <div className="p-12 text-center text-slate-400 italic">कुनै कर्मचारी फेला परेन।</div>
          )}
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;

