import React, { useState, useEffect, useRef } from 'react';
import { ViewState } from '../types';
import { Menu, X, User, Search, Facebook, Mail, ChevronDown, Globe } from 'lucide-react';

interface NavbarProps {
  currentView: ViewState;
  setView: (view: ViewState) => void;
  isAdmin: boolean;
}

const Navbar: React.FC<NavbarProps> = ({ currentView, setView, isAdmin }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [staffDropdownOpen, setStaffDropdownOpen] = useState(false);
  const [currentTime, setCurrentTime] = useState(new Date());
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setStaffDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const toNepaliNumerals = (num: number | string) => {
    const nepaliNums = ['०', '१', '२', '३', '४', '५', '६', '७', '८', '९'];
    return num.toString().split('').map(d => nepaliNums[parseInt(d)] || d).join('');
  };

  const getNepaliDateParts = (date: Date) => {
    const nepaliMonths = ["बैशाख", "जेठ", "असार", "साउन", "भदौ", "असोज", "कात्तिक", "मंसिर", "पुष", "माघ", "फागुन", "चैत"];
    const nepaliDays = ["आइतबार", "सोमबार", "मंगलबार", "बुधबार", "बिहीबार", "शुक्रबार", "शनिबार"];
    const daysInMonths2081 = [31, 31, 32, 32, 31, 30, 30, 29, 30, 29, 30, 30];
    const refDate = new Date("2024-04-13");
    const diffTime = date.getTime() - refDate.getTime();
    const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));

    let year = 2081;
    let monthIndex = 0;
    let day = diffDays + 1;
    if (diffDays < 0) return { year: 2080, month: "चैत", day: 30, dayName: nepaliDays[date.getDay()], time: date.toLocaleTimeString('ne-NP') };
    while (day > daysInMonths2081[monthIndex]) {
      day -= daysInMonths2081[monthIndex];
      monthIndex++;
      if (monthIndex > 11) { monthIndex = 0; year++; }
    }
    return {
      year: toNepaliNumerals(year),
      month: nepaliMonths[monthIndex],
      day: toNepaliNumerals(day),
      dayName: nepaliDays[date.getDay()],
      time: date.toLocaleTimeString('ne-NP', { hour12: false, hour: '2-digit', minute: '2-digit' })
    };
  };

  const dateParts = getNepaliDateParts(currentTime);

  const navItems = [
    { label: 'हाम्रो बारेमा', view: 'ABOUT' as ViewState, hasDropdown: false },
    { label: 'सेवाहरू', view: 'SERVICES' as ViewState, hasDropdown: false },
    { label: 'सूचनाहरू', view: 'NOTICES' as ViewState, hasDropdown: false },
    { label: 'डाउनलोड', view: 'DOWNLOADS' as ViewState, hasDropdown: false },
  ];

  const staffSubItems = [
    { label: 'स्वास्थ्य संस्था व्यवस्थापन समिति', view: 'COMMITTEE' as ViewState },
    { label: 'प्रमुखहरू', view: 'CHIEFS' as ViewState },
    { label: 'हाल कार्यरत कर्मचारीहरू', view: 'CURRENT_STAFF' as ViewState },
    { label: 'पूर्व कर्मचारीहरू', view: 'FORMER_STAFF' as ViewState },
  ];

  const isStaffViewActive = ['COMMITTEE', 'CHIEFS', 'CURRENT_STAFF', 'FORMER_STAFF'].includes(currentView);

  return (
    <header className="w-full flex flex-col z-50 sticky top-0 bg-white">
      {/* Top Blue Bar - Optimized for Mobile */}
      <div className="bg-[#1e3a8a] text-white py-2 md:py-3 px-4 md:px-8 border-b border-white/10">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-3 md:gap-4 text-center md:text-left">
          <div className="flex items-center gap-3 md:gap-4 cursor-pointer" onClick={() => setView('HOME')}>
            <img src="https://upload.wikimedia.org/wikipedia/commons/2/23/Emblem_of_Nepal.svg" alt="Nepal Emblem" className="h-10 md:h-14 w-auto" />
            <div className="flex flex-col items-start">
              <span className="text-[9px] md:text-[11px] font-medium opacity-90">चौदण्डीगढी नगरपालिका</span>
              <h1 className="text-base md:text-xl font-black leading-tight">आधारभूत नगर अस्पताल</h1>
              <span className="text-[9px] md:text-[11px] font-bold opacity-80">बेल्टार, उदयपुर</span>
            </div>
          </div>

          <div className="flex items-center gap-3 md:gap-4 bg-blue-900/40 p-1.5 md:p-2 rounded-xl border border-white/5">
            <img src="https://upload.wikimedia.org/wikipedia/commons/9/9b/Flag_of_Nepal.svg" alt="Nepal Flag" className="h-6 md:h-10 w-auto animate-flag-wave" />
            <div className="flex flex-col border-l border-white/20 pl-3 md:pl-4 text-left">
              <span className="text-[11px] md:text-[13px] font-bold leading-tight">
                वि.सं.: {dateParts.year}-{dateParts.month}-{dateParts.day} {dateParts.dayName}
              </span>
              <span className="text-[10px] md:text-[11px] text-blue-200/80 font-bold leading-tight mt-0.5">
                समय: {dateParts.time}
              </span>
            </div>
          </div>
        </div>
      </div>

      {/* Main Nav - Desktop & Mobile Toggle */}
      <nav className="bg-white text-slate-800 shadow-sm border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-4 md:px-8 flex items-center justify-between h-14">
          <div className="hidden md:flex items-center space-x-1 h-full">
            <button onClick={() => setView('HOME')} className={`px-4 h-full text-sm font-bold border-b-4 transition-all ${currentView === 'HOME' ? 'border-blue-700 bg-blue-50 text-blue-700' : 'border-transparent hover:bg-slate-50'}`}>गृहपृष्ठ</button>

            {navItems.map((item) => (
              <button key={item.label} onClick={() => setView(item.view)} className={`px-4 h-full text-sm font-bold border-b-4 transition-all ${currentView === item.view ? 'border-blue-700 bg-blue-50 text-blue-700' : 'border-transparent hover:bg-slate-50'}`}>
                {item.label}
              </button>
            ))}

            <div className="relative h-full" ref={dropdownRef}>
              <button 
                onClick={() => setStaffDropdownOpen(!staffDropdownOpen)}
                className={`px-4 h-full flex items-center gap-1 text-sm font-bold border-b-4 transition-all ${isStaffViewActive ? 'border-blue-700 bg-blue-50 text-blue-700' : 'border-transparent hover:bg-slate-50'}`}
              >
                कर्मचारीहरू <ChevronDown size={14} className={`opacity-50 transition-transform ${staffDropdownOpen ? 'rotate-180' : ''}`} />
              </button>

              {staffDropdownOpen && (
                <div className="absolute top-full left-0 w-64 bg-white border border-slate-200 shadow-xl rounded-b-xl py-2 animate-in fade-in slide-in-from-top-2">
                  {staffSubItems.map((sub) => (
                    <button
                      key={sub.label}
                      onClick={() => { setView(sub.view); setStaffDropdownOpen(false); }}
                      className={`w-full text-left px-6 py-3 text-sm font-bold hover:bg-blue-50 hover:text-blue-700 transition-colors ${currentView === sub.view ? 'text-blue-700 bg-blue-50' : 'text-slate-700'}`}
                    >
                      {sub.label}
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>

          <div className="flex items-center gap-4 flex-1 md:flex-none justify-end">
            <div className="hidden lg:flex items-center bg-slate-100 rounded-full px-4 py-1.5 border border-slate-200">
              <input type="text" placeholder="खोज्नुहोस्..." className="bg-transparent border-none outline-none text-sm w-32 focus:w-48 transition-all font-medium" />
              <Search size={16} className="text-slate-400" />
            </div>

            <button 
              onClick={() => setView(isAdmin ? 'ADMIN_DASHBOARD' : 'ADMIN_LOGIN')} 
              className="p-2 bg-blue-600 text-white rounded-full hover:bg-blue-700 transition-colors"
              aria-label="Admin Access"
            >
              <User size={18} />
            </button>

            <button 
              onClick={() => setIsOpen(!isOpen)} 
              className="md:hidden p-2 text-slate-600 bg-slate-100 rounded-lg"
              aria-label="Menu"
            >
              {isOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>

        {/* Mobile Menu Drawer */}
        {isOpen && (
          <div className="md:hidden bg-white border-t border-slate-200 animate-in slide-in-from-top duration-300 shadow-lg">
            <div className="flex flex-col p-2">
              <button 
                onClick={() => { setView('HOME'); setIsOpen(false); }} 
                className={`w-full text-left p-4 font-bold rounded-xl ${currentView === 'HOME' ? 'bg-blue-50 text-blue-700' : 'hover:bg-slate-50'}`}
              >
                गृहपृष्ठ
              </button>
              {navItems.map(item => (
                <button 
                  key={item.label} 
                  onClick={() => { setView(item.view); setIsOpen(false); }} 
                  className={`w-full text-left p-4 font-bold rounded-xl ${currentView === item.view ? 'bg-blue-50 text-blue-700' : 'hover:bg-slate-50'}`}
                >
                  {item.label}
                </button>
              ))}

              <div className="mt-2 border-t border-slate-100 pt-2">
                <p className="px-4 py-2 text-[10px] font-black text-slate-400 uppercase tracking-widest">कर्मचारी विवरण</p>
                {staffSubItems.map(sub => (
                  <button 
                    key={sub.label} 
                    onClick={() => { setView(sub.view); setIsOpen(false); }} 
                    className={`w-full text-left py-3 px-6 text-sm font-bold rounded-xl ${currentView === sub.view ? 'bg-blue-50 text-blue-700' : 'text-slate-600 hover:bg-blue-50'}`}
                  >
                    {sub.label}
                  </button>
                ))}
              </div>
            </div>
          </div>
        )}
      </nav>
    </header>
  );
};

export default Navbar;

import React, { useState, useRef } from 'react';
import { Notice, Service, Doctor, TestRate, DownloadItem } from '../types';
import { Plus, Trash2, LayoutDashboard, FileText, Users, LogOut, X, UploadCloud, Image as ImageIcon, ClipboardList, ListPlus, Link as LinkIcon, Building2, UserCircle, Briefcase, Layers, Download, Menu } from 'lucide-react';

interface AdminDashboardProps {
  notices: Notice[];
  services: Service[];
  doctors: Doctor[];
  downloads: DownloadItem[];
  onLogout: () => void;
  updateNotices: (n: Notice[]) => void;
  updateServices: (s: Service[]) => void;
  updateDoctors: (d: Doctor[]) => void;
  updateDownloads: (dw: DownloadItem[]) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  notices, 
  services, 
  doctors, 
  downloads,
  onLogout, 
  updateNotices,
  updateServices,
  updateDoctors,
  updateDownloads
}) => {
  const [activeTab, setActiveTab] = useState<'notices' | 'services' | 'doctors' | 'downloads'>('notices');
  const [isAdding, setIsAdding] = useState(false);
  const [managingRatesFor, setManagingRatesFor] = useState<string | null>(null);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // States for new items
  const [newNotice, setNewNotice] = useState({ title: '', content: '', category: 'General', pdfUrl: '' });
  const [newService, setNewService] = useState({ name: '', description: '', icon: 'Stethoscope' });
  const [newDoctor, setNewDoctor] = useState({ name: '', specialization: '', level: '', department: '', availability: '', image: '', category: 'STAFF' });
  const [newDownload, setNewDownload] = useState({ title: '', category: 'Form', fileUrl: '' });

  // State for new test rate
  const [newRate, setNewRate] = useState({ testName: '', price: '' });

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewDoctor({ ...newDoctor, image: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const triggerFileInput = () => {
    fileInputRef.current?.click();
  };

  const handleAddNotice = () => {
    if (!newNotice.title || !newNotice.content) return;
    const item: Notice = {
      id: Math.random().toString(36).substr(2, 9),
      title: newNotice.title,
      content: newNotice.content,
      date: new Date().toLocaleDateString('ne-NP'),
      category: newNotice.category as any,
      pdfUrl: newNotice.pdfUrl.trim() || undefined
    };
    updateNotices([item, ...notices]);
    setIsAdding(false);
    setNewNotice({ title: '', content: '', category: 'General', pdfUrl: '' });
  };

  const handleAddDownload = () => {
    if (!newDownload.title || !newDownload.fileUrl) return;
    const item: DownloadItem = {
      id: Math.random().toString(36).substr(2, 9),
      title: newDownload.title,
      category: newDownload.category as any,
      fileUrl: newDownload.fileUrl,
      date: new Date().toLocaleDateString('ne-NP')
    };
    updateDownloads([item, ...downloads]);
    setIsAdding(false);
    setNewDownload({ title: '', category: 'Form', fileUrl: '' });
  };

  const handleDeleteDownload = (id: string) => {
    if(confirm('के तपाईं यो फाइल हटाउन चाहनुहुन्छ?')) {
      updateDownloads(downloads.filter(d => d.id !== id));
    }
  };

  const handleDeleteNotice = (id: string) => {
    if(confirm('के तपाईं यो सूचना हटाउन चाहनुहुन्छ?')) {
      updateNotices(notices.filter(n => n.id !== id));
    }
  };

  const handleAddService = () => {
    if (!newService.name || !newService.description) return;
    const item: Service = {
      id: Math.random().toString(36).substr(2, 9),
      name: newService.name,
      description: newService.description,
      icon: newService.icon,
      testRates: []
    };
    updateServices([...services, item]);
    setIsAdding(false);
    setNewService({ name: '', description: '', icon: 'Stethoscope' });
  };

  const handleDeleteService = (id: string) => {
    if(confirm('के तपाईं यो सेवा हटाउन चाहनुहुन्छ?')) {
      updateServices(services.filter(s => s.id !== id));
    }
  };

  const handleAddRate = (serviceId: string) => {
    if (!newRate.testName || !newRate.price) return;
    const updatedServices = services.map(s => {
      if (s.id === serviceId) {
        const rates = s.testRates || [];
        return { ...s, testRates: [...rates, { ...newRate }] };
      }
      return s;
    });
    updateServices(updatedServices);
    setNewRate({ testName: '', price: '' });
  };

  const handleDeleteRate = (serviceId: string, rateIndex: number) => {
    const updatedServices = services.map(s => {
      if (s.id === serviceId && s.testRates) {
        const filteredRates = s.testRates.filter((_, idx) => idx !== rateIndex);
        return { ...s, testRates: filteredRates };
      }
      return s;
    });
    updateServices(updatedServices);
  };

  const handleAddDoctor = () => {
    if (!newDoctor.name || !newDoctor.specialization) return;
    const item: Doctor = {
      id: Math.random().toString(36).substr(2, 9),
      name: newDoctor.name,
      specialization: newDoctor.specialization,
      level: newDoctor.level,
      department: newDoctor.department,
      availability: newDoctor.availability || 'संपर्क गर्नुहोस्',
      image: newDoctor.image || 'https://picsum.photos/seed/doc/400/400',
      category: newDoctor.category as any
    };
    updateDoctors([...doctors, item]);
    setIsAdding(false);
    setNewDoctor({ name: '', specialization: '', level: '', department: '', availability: '', image: '', category: 'STAFF' });
  };

  const handleDeleteDoctor = (id: string) => {
    if(confirm('के तपाईं यो कर्मचारीलाई हटाउन चाहनुहुन्छ? यो कार्य फिर्ता लिन सकिने छैन।')) {
      updateDoctors(doctors.filter(d => d.id !== id));
    }
  };

  const navTabs = [
    { id: 'notices', label: 'सूचना', icon: FileText },
    { id: 'services', label: 'सेवा', icon: LayoutDashboard },
    { id: 'doctors', label: 'कर्मचारी', icon: Users },
    { id: 'downloads', label: 'डाउनलोड', icon: Download },
  ];

  const renderAddForm = () => {
    if (!isAdding) return null;

    return (
      <div className="bg-white p-4 md:p-6 rounded-2xl shadow-lg border border-blue-100 mb-8 animate-in fade-in slide-in-from-top-4">
        <div className="flex justify-between items-center mb-6">
          <h4 className="text-lg font-bold">थप्नुहोस्: {activeTab === 'notices' ? 'नयाँ सूचना' : activeTab === 'services' ? 'नयाँ सेवा' : activeTab === 'doctors' ? 'नयाँ कर्मचारी' : 'नयाँ फाइल'}</h4>
          <button onClick={() => setIsAdding(false)} className="p-2 bg-slate-100 rounded-full text-slate-400 hover:text-slate-600 transition-colors"><X size={20} /></button>
        </div>

        {activeTab === 'notices' && (
          <div className="space-y-4">
            <input type="text" placeholder="सूचनाको शीर्षक" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold" value={newNotice.title} onChange={e => setNewNotice({...newNotice, title: e.target.value})} />
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <select className="w-full border p-3 rounded-xl outline-none" value={newNotice.category} onChange={e => setNewNotice({...newNotice, category: e.target.value})}>
                <option value="General">साधारण (General)</option>
                <option value="Emergency">आपतकालीन (Emergency)</option>
                <option value="Vaccination">खोप (Vaccination)</option>
                <option value="Career">वृत्ति (Career)</option>
              </select>
              <input type="text" placeholder="PDF लिङ्क (ऐच्छिक)" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 text-sm" value={newNotice.pdfUrl} onChange={e => setNewNotice({...newNotice, pdfUrl: e.target.value})} />
            </div>
            <textarea placeholder="सूचनाको विवरण" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 min-h-[100px]" value={newNotice.content} onChange={e => setNewNotice({...newNotice, content: e.target.value})} />
            <button onClick={handleAddNotice} className="bg-blue-600 text-white px-6 py-4 rounded-xl font-black w-full shadow-md hover:bg-blue-700 transition-all active:scale-[0.98]">सूचना सुरक्षित गर्नुहोस्</button>
          </div>
        )}

        {activeTab === 'downloads' && (
          <div className="space-y-4">
            <input type="text" placeholder="फाइलको शीर्षक" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold" value={newDownload.title} onChange={e => setNewDownload({...newDownload, title: e.target.value})} />
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <select className="w-full border p-3 rounded-xl outline-none" value={newDownload.category} onChange={e => setNewDownload({...newDownload, category: e.target.value})}>
                <option value="Form">फारम (Form)</option>
                <option value="Guideline">निर्देशिका (Guideline)</option>
                <option value="Report">प्रतिवेदन (Report)</option>
                <option value="Other">अन्य (Other)</option>
              </select>
              <input type="text" placeholder="फाइलको लिङ्क (URL)" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" value={newDownload.fileUrl} onChange={e => setNewDownload({...newDownload, fileUrl: e.target.value})} />
            </div>
            <button onClick={handleAddDownload} className="bg-blue-600 text-white px-6 py-4 rounded-xl font-black w-full shadow-md hover:bg-blue-700 transition-all active:scale-[0.98]">फाइल सुरक्षित गर्नुहोस्</button>
          </div>
        )}

        {activeTab === 'services' && (
          <div className="space-y-4">
            <input type="text" placeholder="सेवाको नाम" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold" value={newService.name} onChange={e => setNewService({...newService, name: e.target.value})} />
            <select className="w-full border p-3 rounded-xl outline-none" value={newService.icon} onChange={e => setNewService({...newService, icon: e.target.value})}>
              <option value="Stethoscope">Stethoscope (OPD)</option>
              <option value="Ambulance">Ambulance (Emergency)</option>
              <option value="Baby">Baby (Maternity)</option>
              <option value="TestTube">TestTube (Lab)</option>
              <option value="Pill">Pill (Pharmacy)</option>
              <option value="Activity">Activity (Radiology)</option>
            </select>
            <textarea placeholder="सेवाको विवरण" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 min-h-[100px]" value={newService.description} onChange={e => setNewService({...newService, description: e.target.value})} />
            <button onClick={handleAddService} className="bg-blue-600 text-white px-6 py-4 rounded-xl font-black w-full shadow-md hover:bg-blue-700 transition-all active:scale-[0.98]">सेवा सुरक्षित गर्नुहोस्</button>
          </div>
        )}

        {activeTab === 'doctors' && (
          <div className="space-y-4">
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
               <input type="text" placeholder="कर्मचारीको नाम" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold" value={newDoctor.name} onChange={e => setNewDoctor({...newDoctor, name: e.target.value})} />
               <select className="w-full border p-3 rounded-xl outline-none" value={newDoctor.category} onChange={e => setNewDoctor({...newDoctor, category: e.target.value})}>
                 <option value="STAFF">हाल कार्यरत कर्मचारी</option>
                 <option value="CHIEF">प्रमुखहरू</option>
                 <option value="COMMITTEE">व्यवस्थापन समिति</option>
                 <option value="FORMER">पूर्व कर्मचारी</option>
               </select>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
              <input type="text" placeholder="पद (Position)" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" value={newDoctor.specialization} onChange={e => setNewDoctor({...newDoctor, specialization: e.target.value})} />
              <input type="text" placeholder="तह (Level)" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" value={newDoctor.level} onChange={e => setNewDoctor({...newDoctor, level: e.target.value})} />
              <input type="text" placeholder="शाखा (Department)" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" value={newDoctor.department} onChange={e => setNewDoctor({...newDoctor, department: e.target.value})} />
            </div>

            <input type="text" placeholder="उपलब्धता (समय)" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" value={newDoctor.availability} onChange={e => setNewDoctor({...newDoctor, availability: e.target.value})} />

            <div className="flex flex-col items-center justify-center p-6 border-2 border-dashed border-slate-200 rounded-2xl hover:border-blue-400 transition-colors bg-slate-50 cursor-pointer group" onClick={triggerFileInput}>
              <input type="file" ref={fileInputRef} onChange={handleImageUpload} className="hidden" accept="image/*" />
              {newDoctor.image ? (
                <div className="relative">
                  <img src={newDoctor.image} alt="Preview" className="w-24 h-24 md:w-32 md:h-32 object-cover rounded-full border-4 border-white shadow-md" />
                </div>
              ) : (
                <>
                  <UploadCloud size={32} className="text-slate-400 group-hover:text-blue-500 mb-2" />
                  <p className="text-sm font-bold text-slate-500 text-center">फोटो अपलोड गर्नुहोस् (Optional)</p>
                </>
              )}
            </div>

            <button onClick={handleAddDoctor} className="bg-blue-600 text-white px-6 py-4 rounded-xl font-black w-full shadow-lg hover:bg-blue-700 transition-all active:scale-[0.98]">सुरक्षित गर्नुहोस्</button>
          </div>
        )}
      </div>
    );
  };

  const renderRateManager = () => {
    const service = services.find(s => s.id === managingRatesFor);
    if (!service) return null;

    return (
      <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
        <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh] animate-in zoom-in-95">
          <div className="bg-slate-900 p-6 text-white flex justify-between items-center shrink-0">
            <div>
              <h3 className="text-lg md:text-xl font-bold">{service.name}</h3>
              <p className="text-xs text-slate-400 uppercase font-black mt-1">दर रेट व्यवस्थापन</p>
            </div>
            <button onClick={() => setManagingRatesFor(null)} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X size={24} /></button>
          </div>

          <div className="p-4 md:p-6 bg-slate-50 border-b border-slate-200 shrink-0">
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-4">
              <input type="text" placeholder="जाँचको नाम" className="border p-3 rounded-xl text-sm outline-none focus:ring-2 focus:ring-blue-500" value={newRate.testName} onChange={e => setNewRate({...newRate, testName: e.target.value})} />
              <input type="text" placeholder="दर (उदा: रु १००)" className="border p-3 rounded-xl text-sm outline-none focus:ring-2 focus:ring-blue-500" value={newRate.price} onChange={e => setNewRate({...newRate, price: e.target.value})} />
            </div>
            <button onClick={() => handleAddRate(service.id)} className="w-full bg-blue-600 text-white py-3 rounded-xl font-black flex items-center justify-center gap-2 hover:bg-blue-700 transition-all">
              <ListPlus size={18} /> थप्नुहोस्
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-4 md:p-6">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                    <th className="px-2 py-2">जाँच</th>
                    <th className="px-2 py-2 text-right">दर</th>
                    <th className="px-2 py-2 text-right">कार्य</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {service.testRates?.map((rate, idx) => (
                    <tr key={idx} className="hover:bg-slate-50">
                      <td className="px-2 py-4 text-sm font-bold text-slate-800">{rate.testName}</td>
                      <td className="px-2 py-4 text-sm font-black text-blue-700 text-right">{rate.price}</td>
                      <td className="px-2 py-4 text-right">
                        <button onClick={() => handleDeleteRate(service.id, idx)} className="text-slate-400 hover:text-red-600 p-1.5"><Trash2 size={16} /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Sidebar - Desktop */}
      <div className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-white transform ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 md:static transition-transform duration-300 ease-in-out flex flex-col`}>
