               <select 
                 className="w-full border p-4 rounded-xl outline-none bg-white font-black text-blue-900 shadow-sm" 
                 value={newDoctor.featuredRole} 
                 onChange={e => setNewDoctor({...newDoctor, featuredRole: e.target.value})}
