                      <td className="px-6 py-4 text-right">
                        <div className="flex justify-end gap-1">
                          <button onClick={() => handleEditDoctor(doc)} className="p-2 text-slate-400 hover:text-blue-600 transition-colors" title="सम्पादन गर्नुहोस्">
                            <Pencil size={18} />
