export default AdminDashboard;

import React, { useState, useRef } from 'react';
import { Notice, Service, Doctor, DownloadItem } from '../types';
// Fixed: Added 'Info' to the imported icons from lucide-react
import { Plus, Trash2, Pencil, LayoutDashboard, FileText, Users, LogOut, X, UploadCloud, Download, Menu, Briefcase, Layers, UserCircle, Star, FileCheck, AlertCircle, GripVertical, Info } from 'lucide-react';

interface AdminDashboardProps {
  notices: Notice[];
  services: Service[];
  doctors: Doctor[];
  downloads: DownloadItem[];
  onLogout: () => void;
  updateNotices: (n: Notice[]) => void;
  updateServices: (s: Service[]) => void;
  updateDoctors: (d: Doctor[]) => void;
  updateDownloads: (dw: DownloadItem[]) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  notices, 
  services, 
  doctors, 
  downloads,
  onLogout, 
  updateNotices,
  updateServices,
  updateDoctors,
  updateDownloads
}) => {
  const [activeTab, setActiveTab] = useState<'notices' | 'services' | 'doctors' | 'downloads'>('notices');
  const [isAdding, setIsAdding] = useState(false);
  const [editingDoctorId, setEditingDoctorId] = useState<string | null>(null);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const imageInputRef = useRef<HTMLInputElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);

  // States for new/editing items
  const [newNotice, setNewNotice] = useState({ title: '', content: '', category: 'General', pdfUrl: '' });
  const [newService, setNewService] = useState({ name: '', description: '', icon: 'Stethoscope' });
  const [newDoctor, setNewDoctor] = useState({ 
    name: '', specialization: '', level: '', department: '', 
    availability: '', image: '', category: 'STAFF', featuredRole: '' 
  });
  const [newDownload, setNewDownload] = useState({ title: '', category: 'Form', fileUrl: '', fileName: '' });

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewDoctor({ ...newDoctor, image: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewDownload({ 
          ...newDownload, 
          fileUrl: reader.result as string,
          fileName: file.name
        });
      };
      reader.readAsDataURL(file);
    }
  };

  // Drag and Drop Logic
  const handleDragStart = (index: number) => {
    dragItem.current = index;
  };

  const handleDragEnter = (index: number) => {
    dragOverItem.current = index;
  };

  const handleDragEnd = () => {
    if (dragItem.current === null || dragOverItem.current === null) return;

    const newList = [...doctors];
    const draggedItemContent = newList[dragItem.current];
    newList.splice(dragItem.current, 1);
    newList.splice(dragOverItem.current, 0, draggedItemContent);

    dragItem.current = null;
    dragOverItem.current = null;
